    ["Use M+ timer-specific background settings instead of the shared skinning background. Enables the controls below."] = "使用大秘境计时器专用背景设置，而不是共享的皮肤化背景。启用下方控件。",
    ["Use Power Type Color"] = "使用能量类型颜色",
    ["Use QUI's colored timestamp prefix on new chat messages. While enabled, Blizzard's native chat timestamp is suppressed so the two do not stack."] = "为新聊天消息使用 QUI 的彩色时间戳前缀。启用时会抑制 Blizzard 原生聊天时间戳，避免两者叠加。",
    ["Use Time-Based Duration Color"] = "使用基于时间的持续时间颜色",
    ["Use a background color specific to this skin instead of the global default chosen in Theme & Colors."] = "使用此皮肤专用的背景颜色，而不是“主题与颜色”中选择的全局默认值。",
    ["Use a border style specific to this skin instead of the global default chosen in Theme & Colors."] = "使用此皮肤专用的边框样式，而不是“主题与颜色”中选择的全局默认值。",
    ["Use a custom color for the bar background instead of the default subtle fill."] = "使用自定义颜色作为条背景，而不是默认的柔和填充。",
    ["Use a custom font for the combat text instead of inheriting the global QUI default font."] = "使用自定义字体显示战斗文本，而不是继承全局 QUI 默认字体。",
    ["Use a cyan border instead of the quality color on items that belong to a saved equipment set (live views)."] = "对于属于已保存装备套装的物品（实时视图），使用青色边框而不是品质颜色。",
    ["Use a per-spell bar color for this aura-bar spell instead of the container's default bar color."] = "将此光环条法术使用的条颜色改为按法术分别设置，而不是使用容器默认条颜色。",
    ["Use abbreviated distance labels (e.g., Melee/Close/Far) instead of longer phrasing."] = "使用缩写的距离标签（例如 近战/近/远），而不是更长的表述。",
    ["Use green/yellow/red time-based duration colors instead of the static text color."] = "使用绿/黄/红的基于时间持续时间颜色，而不是静态文本颜色。",
    ["Use the Frame Positioning tab to fine-tune frame positions relative to each other."] = "使用“框体定位”选项卡微调框体之间的相对位置。",
    ["Use the Nudge tool for fine-grained pixel adjustments to any anchored element."] = "使用微调工具对任何锚定元素进行像素级精细调整。",
    ["Use the QUI theme accent color for proc glows, or a custom color."] = "使用QUI主题强调色作为触发发光颜色，或使用自定义颜色。",
    ["Use the compact label variant for this slot."] = "为此栏位使用紧凑标签变体。",
    ["Use the compact label variant for this widget."] = "为此小组件使用紧凑标签变体。",
    ["Use |cFFFFFF00/qui layout|r to position frames, then click |cFFFFFF00Save|r."] = "使用 |cFFFFFF00/qui layout|r 放置框体，然后点击 |cFFFFFF00保存|r。",
    ["Use |cFFFFFF00100% Icon Size|r on CDM Essential & Utility bars for best results."] = "在 CDM 核心与实用条上使用 |cFFFFFF00100% 图标尺寸|r 可获得最佳效果。",
    ["Use |cff60A5FA/cdm|r to open the Blizzard Cooldown Settings panel for viewer layout."] = "使用 |cff60A5FA/cdm|r 打开 Blizzard 冷却设置面板以配置查看器布局。",
    ["Use |cff60A5FA/kb|r to set up keybinds by hovering over action buttons and pressing a key."] = "使用 |cff60A5FA/kb|r 通过悬停动作按钮并按键来设置按键绑定。",
    ["Use |cff60A5FA/qui layout|r or the |cff60A5FAQUI Edit Mode|r button to move QUI-managed frames, then fine-tune anchors and nudges in |cff60A5FAFrame Positioning|r"] = "使用 |cff60A5FA/qui layout|r 或 |cff60A5FAQUI 编辑模式|r 按钮移动 QUI 管理的框体，然后在 |cff60A5FA框体定位|r 中微调锚点和位移",
